        var candidates = document.querySelectorAll('p, td, h1, h2, h3, h4, span, div');
        for (var i = 0; i < candidates.length; i++) {
          if (candidates[i].textContent.includes(e.data.text)) {
            target = candidates[i];
            break;
          }
        }
